         FROM offers WHERE id = $1 AND candidate_id = $2`,
        [req.params.id, req.user.id]
      );
      if (candidateResult.rows.length === 0) {
        return res.status(404).json({ error: 'Offer not found' });
      }
      return res.json(candidateResult.rows[0]);
