    });

    let parsed;
    try { parsed = JSON.parse(result); } catch { const m = result.match(/\{[\s\S]*\}/); parsed = m ? JSON.parse(m[0]) : { ready_to_submit: true, completeness_score: 50, issues: [], strengths: [], suggestions: [] }; }
    res.json({ success: true, review: parsed });
