    );

    const projects = await pool.query(
      'SELECT * FROM portfolio_projects WHERE user_id = $1 ORDER BY order_index, start_date DESC',
      [req.user.id]
    );

    res.json({
      success: true,
      profile: profile.rows[0] || {},
