                    )}
                    style={{ height: `${Math.min(100, h)}%` }}
                    title={`${day.date}: ${day.tokensUsed.toLocaleString()} tokens`}
                  />
                )
              })}
            </div>
          </div>
        )}
      </CardContent>
    </Card>
  )
}

