                <p className="text-xs text-muted-foreground">Pool (total/idle/wait)</p>
                <p className="text-sm font-bold tabular-nums">
                  {metrics.database.poolTotal}/{metrics.database.poolIdle}/{metrics.database.poolWaiting}
                </p>
