      </div>
      <div className="flex justify-between mt-1">
        <span className="text-[10px] text-muted-foreground">{hourly[0]?.label}</span>
        <span className="text-[10px] text-muted-foreground">{hourly[hourly.length - 1]?.label}</span>
      </div>
    </div>
  )
}

